using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the AI:ApiKey configuration value or the OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, apiKey));

builder.Services.AddSingleton<Notebook>();
builder.Services.AddSingleton<WebSearchService>();

var app = builder.Build();

var chatClient = app.Services.GetRequiredService<IChatClient>();
var notebook = app.Services.GetRequiredService<Notebook>();
var webSearch = app.Services.GetRequiredService<WebSearchService>();
var loggerFactory = app.Services.GetRequiredService<ILoggerFactory>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
            webSearch.SearchAsync(query),
        "web_search",
        "Search the web for information on a topic. Returns a list of results with titles, snippets, and URLs."),

    AIFunctionFactory.Create(
        ([Description("The title or key topic for this note")] string title,
         [Description("The content to save in the note")] string content) =>
            notebook.AddNote(title, content),
        "add_note",
        "Save a research note. Use this to record important findings from web searches."),

    AIFunctionFactory.Create(
        () => notebook.GetAllNotes(),
        "get_notes",
        "Retrieve all saved research notes to review findings so far."),
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic, you must:
        1. Search the web for relevant information using multiple, varied queries.
        2. Save important findings as notes using the note-taking tool.
        3. After gathering enough information, review your notes and provide a comprehensive summary.

        Always search at least 3 times with different queries to get broad coverage.
        Save a note for each meaningful finding before summarizing.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools,
    loggerFactory: loggerFactory,
    services: app.Services);

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       Research Agent (powered by MAF) ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Research the following topic thoroughly and provide a summary: {topic}",
    session,
    runOptions);

Console.WriteLine();
Console.WriteLine("═══ Research Summary ═══");
Console.WriteLine(response.Text);
Console.WriteLine();

if (notebook.Notes.Count > 0)
{
    Console.WriteLine($"═══ Notes Collected ({notebook.Notes.Count}) ═══");
    foreach (var note in notebook.Notes)
    {
