using System.Web;

namespace ResearchAgent;

/// <summary>
/// Web search tool that uses a search API.
/// Defaults to a simulated search for demo purposes.
/// Set the AI:SearchApiKey configuration value to use a real search provider.
/// </summary>
public sealed class WebSearchService
{
    private readonly HttpClient _httpClient = new();

    public async Task<string> SearchAsync(string query)
    {
        // Attempt a real web search via Google Custom Search API if configured
        var apiKey = Environment.GetEnvironmentVariable("SEARCH_API_KEY");
        var searchEngineId = Environment.GetEnvironmentVariable("SEARCH_ENGINE_ID");

        if (!string.IsNullOrEmpty(apiKey) && !string.IsNullOrEmpty(searchEngineId))
        {
            return await SearchGoogleAsync(query, apiKey, searchEngineId);
        }

        // Fallback: simulated search results for demonstration
        return GetSimulatedResults(query);
    }

    private async Task<string> SearchGoogleAsync(string query, string apiKey, string searchEngineId)
    {
        var encoded = HttpUtility.UrlEncode(query);
        var url = $"https://www.googleapis.com/customsearch/v1?key={apiKey}&cx={searchEngineId}&q={encoded}&num=5";

        var response = await _httpClient.GetAsync(url);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        var items = doc.RootElement.GetProperty("items");

        var results = new List<string>();
        foreach (var item in items.EnumerateArray().Take(5))
        {
            var title = item.GetProperty("title").GetString();
            var snippet = item.GetProperty("snippet").GetString();
            var link = item.GetProperty("link").GetString();
            results.Add($"Title: {title}\nSnippet: {snippet}\nURL: {link}");
        }

        return string.Join("\n---\n", results);
    }

    private static string GetSimulatedResults(string query)
    {
        var queryLower = query.ToLowerInvariant();

        var results = new List<(string Title, string Snippet, string Url)>
        {
            ($"Overview of {query}",
             $"A comprehensive overview covering the key aspects of {query}. This topic has gained significant attention in recent years due to its wide-ranging implications across multiple fields.",
             $"https://example.com/overview-{Slug(query)}"),

            ($"Latest Research on {query}",
             $"Recent studies and findings related to {query}. Researchers have made notable progress in understanding the fundamental mechanisms and practical applications.",
             $"https://example.com/research-{Slug(query)}"),

            ($"{query} - Historical Context and Evolution",
             $"The historical development of {query} from its origins to the present day. Key milestones include early theoretical work and subsequent empirical validation.",
             $"https://example.com/history-{Slug(query)}"),

            ($"Practical Applications of {query}",
             $"Real-world applications and use cases of {query}. Industries ranging from technology to healthcare have adopted approaches based on these principles.",
             $"https://example.com/applications-{Slug(query)}"),

            ($"Future Directions in {query}",
             $"Expert predictions and emerging trends related to {query}. The field is expected to see significant advances in the coming years.",
             $"https://example.com/future-{Slug(query)}"),
        };

        var output = results.Select(r =>
            $"Title: {r.Title}\nSnippet: {r.Snippet}\nURL: {r.Url}");

        return string.Join("\n---\n", output);
    }

    private static string Slug(string text) =>
        text.ToLowerInvariant().Replace(' ', '-').Replace("\"", "");
}

